@spec tm_rebuild_rule_spec  src=tests/specs/tm_rebuild_rule_spec.lua  loc=515  sha=d415ad4  cases=20
@exercises midiManager (h.fm), trackerManager (h.tm), dataStore (h.ds), configManager (h.cm)
@surface   fm:dump, tm:markSwingStale, fm:notes, fm:modify, fm:assign, fm:ccs, tm:getChannel, tm:assignEvent, tm:flush, tm:rebuild, ds:assign, cm:set
@harness   mk{seed.notes, seed.ccs}

# Intent
  Phase 2 (two-frame timing): the rebuild rule. tm reconciles raw ppq
  with ppqL on every rebuild under three branches:
    - stale=true  & ppqL present  → raw rebuilt from ppqL (+ delay)
    - stale=false & raw matches   → no-op (steady state)
    - stale=false & raw disagrees → ppqL rederived from raw
  The rpb mark survives as authorship provenance but no longer gates the rule.

# Helpers
  @fn noteByPitch(dump, pitch)  @ 13-15
  @fn ccByCC(dump, ccNum)  @ 16-20

# Cases
  @case 'note with no ppqL gets ppqL written on first rebuild'  [harness]  @ 26-37
  @case 'note with ppqL disagreeing with raw gets ppqL rederived'  [harness]  @ 41-55
  @case 'cc with no ppqL gets ppqL written and uuid allocated'  [harness]  @ 59-69
  @case 'note with matching ppqL is left alone'  [harness]  @ 75-88
  @case 'matching ppqL under c58 is steady-state (predicted=raw within ε)'  [harness]  @ 92-109
  @case 'markSwingStale rebuilds raw from ppqL on next rebuild and clears the flag'  [harness]  @ 115-147
  @case 'markSwingStale restamps cc-event loc so column writes route correctly'  [harness]  @ 151-178
  @case 'markSwingStale(nil) marks all 16 channels'  [harness]  @ 182-204
